// Obtener los datos del nodo anterior "Get list of contacts"
const contacts = $input.all();

// Inicializar variables
let existeContacto = false;
let primerContacto = null;

// Verificar si hay datos en la respuesta
if (contacts.length > 0) {
  const data = contacts[0].json;

  // Validar estructura del JSON
  if (data && data._embedded && Array.isArray(data._embedded.contacts)) {
    const listaContactos = data._embedded.contacts;

    // Verificar si existe algún contacto con ID válido
    if (listaContactos.length > 0) {
      const contactoConID = listaContactos.find(c => c.id && typeof c.id === 'number');
      if (contactoConID) {
        existeContacto = true;
        primerContacto = contactoConID;
      }
    }
  }
}

// Retornar resultado
return [{
  json: {
    existe_contacto: existeContacto,
    cantidad_contactos: primerContacto ? 1 : 0,
    primer_contacto: primerContacto
  }
}];

// Sanitize LLM placeholder leaks (some-xxx, undefined, null strings, empty)
const isPlaceholder = (v) => !v || typeof v !== 'string' || /^(some-|<|undefined$|null$|n\/a$)/i.test(v.trim());

const input = $input.first().json;
const fechaStr = input.Fecha_preferida;

// Parsear la fecha considerando zona horaria de Madrid
let fecha;

if (fechaStr.includes('+') || fechaStr.includes('Z')) {
  fecha = new Date(fechaStr);
} else {
  const testDate = new Date(fechaStr);
  const mes = testDate.getMonth();
  const esHorarioVerano = mes >= 2 && mes <= 9;
  const offset = esHorarioVerano ? '+02:00' : '+01:00';
  fecha = new Date(fechaStr + offset);
}

// Timestamp Unix (segundos) para Kommo
const segundos = Math.floor(fecha.getTime() / 1000);

// ISO 8601 para Google Calendar
const fechaInicioISO = fecha.toISOString();

// Fin = inicio + 30 minutos
const fechaFin = new Date(fecha.getTime() + 30 * 60 * 1000);
const fechaFinISO = fechaFin.toISOString();

// Fecha legible para email
const fechaInicioMadrid = fecha.toLocaleString('es-ES', { 
  timeZone: 'Europe/Madrid',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

const _idealista = isPlaceholder(input.idealista_id) ? '' : input.idealista_id;
const _direccion = isPlaceholder(input.direccion) ? '' : input.direccion;
const _thumbnail = isPlaceholder(input.thumbnail) ? '' : input.thumbnail;
return [
  {
    json: {
      ...input,
      idealista_id: _idealista,
      direccion: _direccion,
      thumbnail: _thumbnail,
      segundos: segundos,
      fechaInicioISO: fechaInicioISO,
      fechaFinISO: fechaFinISO,
      fechaInicioMadrid: fechaInicioMadrid,
      doctorAsignado: "Equipo Simarro Properties",
      leadName: input.nombre + "||" + input.Tipo_de_servicio + "||" + input.numero_de_telefono
    }
  }
];

