const fechaStr = $input.first().json["Fecha preferida"];

// Parsear la fecha de forma explícita considerando la zona horaria de Madrid
let fecha;

// Si la fecha ya incluye zona horaria (+01:00 o +02:00), usarla directamente
if (fechaStr.includes('+') || fechaStr.includes('Z')) {
  fecha = new Date(fechaStr);
} else {
  // Si no tiene zona horaria, agregarla manualmente
  // Formato esperado: "2025-10-21T15:30:00"
  // Determinar si estamos en horario de verano (CET +01:00) o invierno (CEST +02:00)
  const testDate = new Date(fechaStr);
  const mes = testDate.getMonth(); // 0-11

  // Horario de verano en Europa: último domingo de marzo hasta último domingo de octubre
  // Para simplificar: marzo-octubre = +02:00, resto = +01:00
  const esHorarioVerano = mes >= 2 && mes <= 9; // Marzo (2) a Octubre (9)
  const offset = esHorarioVerano ? '+02:00' : '+01:00';

  fecha = new Date(fechaStr + offset);
}

// Convertir a timestamp Unix (segundos)
const segundos = Math.floor(fecha.getTime() / 1000);

return [
  { 
    json: { 
      segundos: segundos,
      debug_fechaOriginal: fechaStr,
      debug_fechaUTC: fecha.toISOString(),
      debug_fechaMadrid: fecha.toLocaleString('es-ES', { 
        timeZone: 'Europe/Madrid',
        dateStyle: 'full',
        timeStyle: 'long'
      })
    }
  }
];

